SELECT HOMPI_ID ,DIARY_ID,DIARY_CONTENT,AVAIL_STATUS
FROM HOMPI_DIARY
WHERE 1=1
AND HOMPI_ID = #{hompiId}

    AND DIARY_ID = #{diaryId}



        AND AVAIL_STATUS IN ('31', '32', '33')


        AND AVAIL_STATUS IN ('32', '33')


        AND AVAIL_STATUS = #{availStatus}



    ORDER BY FOLDER_ID ,INSERT_DT DESC
    LIMIT 1

SELECT HOMPI_ID,DIARY_ID,DIARY_CONTENT,AVAIL_STATUS
    FROM HOMPI_DIARY
WHERE HOMPI_ID = #{hompiId}
    AND FOLDER_ID = #{folderId}
    AND DATE(INSERT_DT) = #{day}

mapper.update:
UPDATE HOMPI_DIARY
SET DIARY_CONTENT = #{diaryContent},
AVAIL_STATUS = #{availStatus}
WHERE DIARY_ID = #{diaryId}
AND HOMPI_ID = #{hompiId}

mapper.delete:
DELETE A,B
FROM HOMPI_DIARY A
    LEFT JOIN HOMPI_DIARY_COMMENT B
        ON A.DIARY_ID = B.DIARY_ID
WHERE A.DIARY_ID = #{diaryId}
    AND A.HOMPI_ID = #{hompiId}
